DROP VIEW IF EXISTS "usuarioFullInfo";
DROP TABLE IF EXISTS usuario;
DROP TABLE IF EXISTS "programaEducativo";
DROP TABLE IF EXISTS rol;
DROP TABLE IF EXISTS "tipoUsuario";

CREATE TABLE "programaEducativo" (
  "idPrograma" int GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  nombre varchar(100) NOT NULL,
  estatus bit(1) NOT NULL
);

CREATE TABLE rol (
  idrol int GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  nombre varchar(50) NOT NULL,
  estatus bit(1) NOT NULL
);

CREATE TABLE "tipoUsuario" (
  "idTipo" int GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  nombre varchar(50) NOT NULL,
  estatus bit(1) NOT NULL
);

CREATE TABLE usuario (
  "idUsuario" int GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
  nombre varchar(50) NOT NULL,
  "apellidoPaterno" varchar(50) NOT NULL,
  "apellidoMaterno" varchar(50),
  "claveUsuario" varchar(10) NOT NULL,
  email varchar(255) NOT NULL,
  telefono varchar(10),
  username varchar(30) NOT NULL,
  password text NOT NULL,
  estatus bit(1) NOT NULL,
  "idRol" int NOT NULL,
  "idTipoUsuario" int NOT NULL,
  "idProgramaEducativo" int NOT NULL,
  "tiempoCreacion" timestamp,
  "tempoActualizacion" timestamp,
  CONSTRAINT usuario_idrol_fkey FOREIGN KEY ("idRol") REFERENCES rol(idrol),
  CONSTRAINT usuario_idtipousuario_fkey FOREIGN KEY ("idTipoUsuario") REFERENCES "tipoUsuario"("idTipo"),
  CONSTRAINT usuario_idprograma_fkey FOREIGN KEY ("idProgramaEducativo") REFERENCES "programaEducativo"("idPrograma")
);

