CREATE VIEW "usuarioFullInfo" AS
SELECT u."idUsuario",
       u.nombre,
       u."apellidoPaterno",
       u."apellidoMaterno",
       u."claveUsuario",
       u.email,
       u.telefono,
       u.username,
       u.password,
       u.estatus,
       u."idRol",
       r.nombre AS rol,
       u."idTipoUsuario",
       tu.nombre AS "tipoUsuario",
       u."idProgramaEducativo",
       pe.nombre AS "programaEducativo",
       u."tiempoCreacion",
       u."tempoActualizacion"
FROM usuario u
JOIN rol r ON r.idrol = u."idRol"
JOIN "tipoUsuario" tu ON tu."idTipo" = u."idTipoUsuario"
JOIN "programaEducativo" pe ON pe."idPrograma" = u."idProgramaEducativo";

SELECT setval(pg_get_serial_sequence('"programaEducativo"', 'idPrograma'), 7, true);
SELECT setval(pg_get_serial_sequence('rol', 'idrol'), 2, true);
SELECT setval(pg_get_serial_sequence('"tipoUsuario"', 'idTipo'), 3, true);
SELECT setval(pg_get_serial_sequence('usuario', 'idUsuario'), 1, true);
